function factorize(n) {
    const factors = [];
    let divisor = 2;

    while (divisor * divisor <= n) {
        while (n % divisor === 0) {
            factors.push(divisor);
            n = Math.floor(n / divisor);
        }
        divisor++;
    }

    if (n > 1) {
        factors.push(n);
    }

    return factors;
}

