function prime_fib(n) {
    const isPrime = (num) => {
        if (num < 2) return false;
        if (num === 2) return true;
        if (num % 2 === 0) return false;
        for (let i = 3; i * i <= num; i += 2) {
            if (num % i === 0) return false;
        }
        return true;
    };

    let count = 0;
    let a = 1;
    let b = 1;

    while (true) {
        const next = a + b;
        a = b;
        b = next;

        if (isPrime(b)) {
            count++;
            if (count === n) return b;
        }
    }
}

