function modp(n, p) {
    if (n === 0) return 1 % p;
    let result = 1;
    let base = 2 % p;
    let exp = n;

    while (exp > 0) {
        if (exp % 2 === 1) {
            result = (result * base) % p;
        }
        base = (base * base) % p;
        exp = Math.floor(exp / 2);
    }

    return result;
}

