function largest_prime_factor(n) {
  let maxPrime = -1;

  // Remove all factors of 2
  while (n % 2 === 0) {
    maxPrime = 2;
    n = Math.floor(n / 2);
  }

  // Check for odd factors from 3 onwards
  let i = 3;
  while (i * i <= n) {
    while (n % i === 0) {
      maxPrime = i;
      n = Math.floor(n / i);
    }
    i += 2;
  }

  // If n is now greater than 1, then it's a prime factor itself
  if (n > 1) {
    maxPrime = n;
  }

  return maxPrime;
}
