function minPath(grid, k) {
    const n = grid.length;
    if (k === 0) return [];

    // Find all positions of the smallest value to start BFS
    let minVal = Infinity;
    for (let i = 0; i < n; i++) {
        for (let j = 0; j < n; j++) {
            if (grid[i][j] < minVal) {
                minVal = grid[i][j];
            }
        }
    }

    // Collect all starting positions with the minimum value
    const starts = [];
    for (let i = 0; i < n; i++) {
        for (let j = 0; j < n; j++) {
            if (grid[i][j] === minVal) {
                starts.push([i, j]);
            }
        }
    }

    // If k is 1, return just the minimum value
    if (k === 1) return [minVal];

    // Directions: up, down, left, right
    const dirs = [[-1, 0], [1, 0], [0, -1], [0, 1]];

    // We'll use BFS level by level to build the lexicographically smallest path
    // At each step, we keep only the positions that are part of the optimal path so far

    let currentPositions = starts;
    const result = [minVal];

    for (let step = 1; step < k; step++) {
        // Find the minimum value reachable from any current position
        let nextMinVal = Infinity;

        for (const [r, c] of currentPositions) {
            for (const [dr, dc] of dirs) {
                const nr = r + dr;
                const nc = c + dc;
                if (nr >= 0 && nr < n && nc >= 0 && nc < n) {
                    if (grid[nr][nc] < nextMinVal) {
                        nextMinVal = grid[nr][nc];
                    }
                }
            }
        }

        result.push(nextMinVal);

        // Collect all positions that have the nextMinVal and are reachable from currentPositions
        const nextPositions = new Set();
        for (const [r, c] of currentPositions) {
            for (const [dr, dc] of dirs) {
                const nr = r + dr;
                const nc = c + dc;
                if (nr >= 0 && nr < n && nc >= 0 && nc < n) {
                    if (grid[nr][nc] === nextMinVal) {
                        nextPositions.add(`${nr},${nc}`);
                    }
                }
            }
        }

        // Convert back to array of coordinates
        currentPositions = [];
        for (const pos of nextPositions) {
            const [r, c] = pos.split(',').map(Number);
            currentPositions.push([r, c]);
        }
    }

    return result;
}

function tri(n) {
    if (n === 0) return [1];

    const result = new Array(n + 1);
    result[0] = 1;
    result[1] = 3;

    for (let i = 2; i <= n; i++) {
        if (i % 2 === 0) {
            result[i] = 1 + i / 2;
        } else {
            // For odd i, we need tri(i-1), tri(i-2), and tri(i+1)
            // Since i is odd, i+1 is even, so we can compute it directly
            const nextEven = i + 1;
            const triNextEven = 1 + nextEven / 2;
            result[i] = result[i - 1] + result[i - 2] + triNextEven;
        }
    }

    return result;
}

function digits(n) {
