        if (digit % 2 !== 0) {
            product *= digit;
            hasOdd = true;
        }
        n = Math.floor(n / 10);
    }
    return hasOdd ? product : 0;
}

function is_nested(s) {
    let depth = 0;
    let maxDepth = 0;

    for (let i = 0; i < s.length; i++) {
        if (s[i] === '[') {
            depth++;
            if (depth > maxDepth) {
                maxDepth = depth;
            }
        } else if (s[i] === ']') {
            if (depth === 0) return false;
            depth--;
        }
    }

    // If we never reached a depth of 2, no nesting occurred in any valid subsequence
    return maxDepth >= 2 && depth === 0;
}

function sum_squares(lst) {
