function check_if_last_char_is_a_letter(txt) {
    if (!txt || txt.length === 0) return false;

    const lastChar = txt[txt.length - 1];

    // Check if the last character is an alphabetical letter
    if (!/[a-zA-Z]/.test(lastChar)) {
        return false;
    }

    // If the string ends with a space, the last char is not part of a word (but we already checked it's a letter)
    // However, the requirement says "is not a part of a word". 
    // A word is separated by spaces. So if the last character is a letter and there's no space after it, 
    // it IS part of a word. We need the last char to be a letter AND NOT part of a word.
    // This implies the last character must be a letter that stands alone as a "word" or is separated from the previous word by space?
    // Let's re-read: "is not a part of a word". 
    // In "apple pie", 'e' is part of "pie".
    // In "apple pi e", 'e' is its own word. Is it "part of a word"? It IS the word. 
    // The examples clarify:
    // "apple pie" -> false (e is part of "pie")
    // "apple pi e" -> true (e is a standalone word)
    // "apple pi e " -> false (last char is space, not letter)

    // So the logic is:
    // 1. Last char must be a letter.
    // 2. The character immediately preceding it (if exists) must be a space, OR the string length is 1.
    // Because if there's no space before it, it's attached to the previous characters, making it part of that word.

    const len = txt.length;
    if (len === 1) {
        return /[a-zA-Z]/.test(lastChar);
    }

    const prevChar = txt[len - 2];

    // If the previous character is a space, then the last letter is a standalone word (not part of a larger word).
    if (prevChar === ' ') {
        return true;
    }

    // If the previous character is not a space, the last letter is attached to it, so it's part of a word.
    return false;
}

