function get_max_triples(n) {
    if (n < 3) return 0;

    let count0 = 0; // remainder 0 mod 3
    let count1 = 0; // remainder 1 mod 3
    let count2 = 0; // remainder 2 mod 3

    for (let i = 1; i <= n; i++) {
        const val = i * i - i + 1;
        const rem = ((val % 3) + 3) % 3;
        if (rem === 0) count0++;
        else if (rem === 1) count1++;
        else count2++;
    }

    let total = 0;

    // All three remainders are 0: 0+0+0 = 0 mod 3
    if (count0 >= 3) {
        total += (count0 * (count0 - 1) * (count0 - 2)) / 6;
    }

    // All three remainders are 1: 1+1+1 = 3 = 0 mod 3
    if (count1 >= 3) {
        total += (count1 * (count1 - 1) * (count1 - 2)) / 6;
    }

    // All three remainders are 2: 2+2+2 = 6 = 0 mod 3
    if (count2 >= 3) {
        total += (count2 * (count2 - 1) * (count2 - 2)) / 6;
    }

    // One of each: 0+1+2 = 3 = 0 mod 3
    total += count0 * count1 * count2;

    return total;
}

