function make_palindrome(string) {
    if (string === "") return "";

    const n = string.length;

    // Find the longest palindromic suffix
    let maxLen = 0;
    for (let i = 0; i < n; i++) {
        let isPalindrome = true;
        let len = n - i;
        for (let j = 0; j < Math.floor(len / 2); j++) {
            if (string[i + j] !== string[n - 1 - j]) {
                isPalindrome = false;
                break;
            }
        }
        if (isPalindrome) {
            maxLen = len;
            break; // Found the longest one since we start from i=0
        }
    }

    // The prefix that needs to be reversed and appended
    const prefixToReverse = string.substring(0, n - maxLen);
    const reversedPrefix = prefixToReverse.split('').reverse().join('');

    return string + reversedPrefix;
}

