function factorize(n) {
    const factors = [];
    let divisor = 2;
    while (n > 1) {
        while (n % divisor === 0) {
            factors.push(divisor);
            n /= divisor;
        }
        divisor++;
        if (divisor * divisor > n && n > 1) {
