function minPath(grid, k) {
    const n = grid.length;
    if (k === 0) return [];

    // Find the position of the minimum value (which is always 1)
    let startRow = -1, startCol = -1;
    for (let i = 0; i < n; i++) {
        for (let j = 0; j < n; j++) {
            if (grid[i][j] === 1) {
                startRow = i;
                startCol = j;
                break;
            }
        }
        if (startRow !== -1) break;
    }

    // If k is 1, just return [1]
    if (k === 1) return [1];

    // Directions: up, down, left, right
    const dirs = [[-1, 0], [1, 0], [0, -1], [0, 1]];

    // We need to find the lexicographically smallest path of length k starting from 1.
    // Since we want the lexicographically smallest path, at each step we should choose
    // the neighbor with the smallest value. However, if there are multiple neighbors
    // with the same smallest value, we might need to look ahead. But since the problem
    // guarantees a unique answer and values are distinct (1 to N*N), at any cell,
    // all neighbors have distinct values. So we can greedily pick the smallest neighbor.

    let path = [grid[startRow][startCol]];
    let currRow = startRow;
    let currCol = startCol;

    for (let step = 1; step < k; step++) {
        let minVal = Infinity;
        let nextRow = -1, nextCol = -1;

        // Check all neighbors
        for (const [dr, dc] of dirs) {
            const nr = currRow + dr;
            const nc = currCol + dc;

            if (nr >= 0 && nr < n && nc >= 0 && nc < n) {
                if (grid[nr][nc] < minVal) {
                    minVal = grid[nr][nc];
                    nextRow = nr;
                    nextCol = nc;
                }
            }
        }

        // Move to the neighbor with the smallest value
        currRow = nextRow;
        currCol = nextCol;
        path.push(grid[currRow][currCol]);
    }

    return path;
}

