function do_algebra(operator, operand) {
    let tokens = [operand[0]];
    for (let i = 0; i < operator.length; i++) {
        tokens.push(operator[i]);
        tokens.push(operand[i + 1]);
    }

    // Convert to postfix using Shunting-yard algorithm
    const outputQueue = [];
    const opStack = [];

    const precedence = {
        '+': 1,
        '-': 1,
        '*': 2,
        '//': 2,
        '**': 3
    };

    for (const token of tokens) {
        if (typeof token === 'number') {
            outputQueue.push(token);
        } else {
            while (
                opStack.length > 0 &&
                opStack[opStack.length - 1] !== '(' &&
                precedence[opStack[opStack.length - 1]] >= precedence[token]
            ) {
                outputQueue.push(opStack.pop());
            }
            opStack.push(token);
        }
    }

    while (opStack.length > 0) {
        outputQueue.push(opStack.pop());
    }

    // Evaluate postfix expression
    const stack = [];
    for (const token of outputQueue) {
        if (typeof token === 'number') {
            stack.push(token);
        } else {
            const b = stack.pop();
            const a = stack.pop();
            let result;
            switch (token) {
                case '+':
                    result = a + b;
                    break;
                case '-':
                    result = a - b;
                    break;
                case '*':
                    result = a * b;
                    break;
                case '//':
                    result = Math.floor(a / b);
                    break;
                case '**':
                    result = Math.pow(a, b);
                    break;
            }
            stack.push(result);
        }
    }

    return stack[0];
}

