    for (let i = 0; i < n; i++) {
        for (let j = 0; j < n; j++) {
            if (grid[i][j] === minVal) {
                starts.push([i, j]);
            }
        }
    }

    // If k is 1, just return the minimum value
    if (k === 1) {
        return [minVal];
    }

    // Directions: up, down, left, right
    const dirs = [[-1, 0], [1, 0], [0, -1], [0, 1]];

    // BFS-like approach to build the lexicographically smallest path
    // We maintain a list of current positions for all paths that are tied so far
    let currentPositions = starts;
    let result = [minVal];

    for (let step = 1; step < k; step++) {
        // Find the minimum value reachable from any current position
        let nextMinVal = Infinity;

        for (const [r, c] of currentPositions) {
            for (const [dr, dc] of dirs) {
                const nr = r + dr;
                const nc = c + dc;
                if (nr >= 0 && nr < n && nc >= 0 && nc < n) {
                    if (grid[nr][nc] < nextMinVal) {
                        nextMinVal = grid[nr][nc];
                    }
                }
            }
        }

        result.push(nextMinVal);

        // Collect all positions that have the nextMinVal and are reachable from currentPositions
        let nextPositions = [];
        for (const [r, c] of currentPositions) {
            for (const [dr, dc] of dirs) {
                const nr = r + dr;
                const nc = c + dc;
                if (nr >= 0 && nr < n && nc >= 0 && nc < n) {
                    if (grid[nr][nc] === nextMinVal) {
                        // Avoid duplicates in nextPositions
                        let found = false;
                        for (const pos of nextPositions) {
                            if (pos[0] === nr && pos[1] === nc) {
                                found = true;
                                break;
                            }
                        }
                        if (!found) {
                            nextPositions.push([nr, nc]);
                        }
                    }
                }
            }
        }

        currentPositions = nextPositions;
    }

    return result;
}

function tri(n) {
    if (n === 0) return [1];
    if (n === 1) return [1, 3];

    const result = new Array(n + 1);
    result[0] = 1;
    result[1] = 3;

    for (let i = 2; i <= n; i++) {
        if (i % 2 === 0) {
            result[i] = 1 + i / 2;
        } else {
            // For odd i, we need tri(i+1). Since i is odd, i+1 is even.
            // We can compute tri(i+1) using the even formula: 1 + (i+1)/2
            const nextEven = 1 + (i + 1) / 2;
            result[i] = result[i - 1] + result[i - 2] + nextEven;
        }
    }

    return result;
}

