function check_if_last_char_is_a_letter(txt) {
    if (!txt || txt.length === 0) return false;

    const lastChar = txt[txt.length - 1];

    // Check if the last character is an alphabetical letter
    if (!/[a-zA-Z]/.test(lastChar)) {
        return false;
    }

    // If the string ends with a space, the last char isn't part of a word (but it's not a letter either, handled above)
    // We need to check if the last character is a standalone word.
    // A standalone word means:
    // 1. It is preceded by a space OR it is the only character in the string.
    // 2. It is not followed by anything (it's the end).

    const trimmed = txt.trimEnd();
    if (trimmed.length === 0) return false;

    // If after trimming end spaces, the last char is different from original last char, 
    // it means original ended with space -> false (already handled by letter check, but for logic clarity)
    if (txt[txt.length - 1] !== trimmed[trimmed.length - 1]) {
        return false;
    }

    // Check the character before the last one in the trimmed string
    const len = trimmed.length;
    if (len === 1) {
        // Single character string, and it's a letter -> true
        return true;
    }

    const prevChar = trimmed[len - 2];
    // If the previous character is a space, then the last char is a standalone word
    if (prevChar === ' ') {
        return true;
    }

    return false;
}

