function file_name_check(file_name) {
  const dotIndex = file_name.indexOf('.');
  if (dotIndex === -1 || dotIndex !== file_name.lastIndexOf('.')) {
    return 'No';
  }

  const namePart = file_name.substring(0, dotIndex);
  const extPart = file_name.substring(dotIndex + 1);

  if (namePart.length === 0) {
    return 'No';
  }

  const firstChar = namePart[0];
  if (!/^[A-Za-z]$/.test(firstChar)) {
    return 'No';
  }

  const digitCount = (file_name.match(/\d/g) || []).length;
  if (digitCount > 3) {
    return 'No';
  }

  const validExtensions = ['txt', 'exe', 'dll'];
  if (!validExtensions.includes(extPart)) {
    return 'No';
  }

  return 'Yes';
}

