    // "apple pie": last char 'e'. Word is "pie". 'e' is part of "pie". Result: false.
    // "apple pi e": last char 'e'. Word is "e". 'e' is the whole word. Result: true.
    // "apple pi e ": last char ' '. Not a letter. Result: false.
    // "": empty. Result: false.

    // Hypothesis: The condition "is not a part of a word" actually means "is a word by itself" (i.e., the word has length 1).
    // Or perhaps it means "the character is isolated".
    // If the last word has length > 1, then the last char is "part of" that word (not the whole thing).
    // If the last word has length == 1, then the last char IS the word.
    // The prompt says "is not a part of a word". This is linguistically ambiguous.
    // But based on examples:
    // "pie" -> 'e' is part of "pie" -> false.
    // "e" -> 'e' is the word "e" -> true.
    // So the logic seems to be: The last character must be a letter, AND the word it belongs to must be exactly that single character.

    // Let's verify with "apple pi e". Words: ["apple", "pi", "e"]. Last word is "e". Length 1. True.
    // "apple pie". Words: ["apple", "pie"]. Last word is "pie". Length 3. False.

    // Algorithm:
    // 1. Trim trailing spaces? No, "apple pi e " -> last char is space, false.
    // 2. If last char is not a letter, return false.
    // 3. Find the word that the last character belongs to.
    //    Since we are at the end of the string, we look backwards until we hit a space or start of string.
    // 4. Check if the length of that word is exactly 1.

    const n = txt.length;
    const lastChar = txt[n - 1];

    if (!/[a-zA-Z]/.test(lastChar)) {
        return false;
    }

    // Find the start of the last word
    let i = n - 1;
    while (i >= 0 && txt[i] !== ' ') {
        i--;
    }

    // The word is from i+1 to n-1
    const wordLength = (n - 1) - (i + 1) + 1;

    return wordLength === 1;
}

