function make_palindrome(string) {
    if (string.length === 0) return "";

    // Find the longest postfix of string that is a palindrome
    let start = -1;
    for (let i = 0; i < string.length; i++) {
        // Check if substring from i to end is a palindrome
        let sub = string.substring(i);
        if (isPalindrome(sub)) {
            start = i;
            break;
        }
    }

    // The prefix before the palindromic suffix
    let prefix = string.substring(0, start);
    // Reverse the prefix and append to the end
    let reversedPrefix = prefix.split('').reverse().join('');

    return string + reversedPrefix;
}

function isPalindrome(str) {
