function sort_third(l) {
    // Extract values at indices divisible by 3 (0, 3, 6, ...)
    const valuesAtDivByThree = [];
    for (let i = 0; i < l.length; i++) {
        if (i % 3 === 0) {
            valuesAtDivByThree.push(l[i]);
        }
    }

    // Sort these values
    valuesAtDivByThree.sort((a, b) => a - b);

    // Create the result array
    const result = [...l];
    let indexInSorted = 0;
    for (let i = 0; i < l.length; i++) {
        if (i % 3 === 0) {
            result[i] = valuesAtDivByThree[indexInSorted];
            indexInSorted++;
        }
    }

    return result;
}

