```javascript
function sort_even(l) {
    // Extract values at even indices
    const evenValues = [];
    for (let i = 0; i < l.length; i += 2) {
        evenValues.push(l[i]);
    }

    // Sort the even-indexed values
    evenValues.sort((a, b) => a - b);

    // Create result array by copying original
    const result = [...l];

    // Place sorted even values back into even indices
    let evenIndex = 0;
    for (let i = 0; i < result.length; i += 2) {
        result[i] = evenValues[evenIndex];
        evenIndex++;
    }

    return result;
}
```

