```javascript
function fib4(n) {
    if (n === 0 || n === 1 || n === 3) return 0;
    if (n === 2) return 2;

    let a = 0; // fib4(0)
    let b = 0; // fib4(1)
    let c = 2; // fib4(2)
    let d = 0; // fib4(3)

    for (let i = 4; i <= n; i++) {
        let next = a + b + c + d;
        a = b;
        b = c;
        c = d;
        d = next;
    }

    return d;
}
```

```javascript
function median(l) {
    const sorted = l.slice().sort((a, b) => a - b);
    const len = sorted.length;
    if (len % 2 === 1) {
        return sorted[Math.floor(len / 2)];
    } else {
        return (sorted[len / 2 - 1] + sorted[len / 2]) / 2;
    }
}
