```javascript
function modp(n, p) {
    if (p === 1) return 0;
    let result = 1;
    let base = 2n % BigInt(p);
    let exp = BigInt(n);

    while (exp > 0n) {
        if (exp % 2n === 1n) {
            result = (result * base) % BigInt(p);
        }
        exp = exp / 2n;
        base = (base * base) % BigInt(p);
    }

    return Number(result);
}
```

