```javascript
function vowels_count(s) {
    const vowels = new Set(['a', 'e', 'i', 'o', 'u']);
    let count = 0;

    for (let i = 0; i < s.length; i++) {
        const char = s[i].toLowerCase();

        // Check if it's a standard vowel
        if (vowels.has(char)) {
            count++;
        }
        // Check if 'y' is at the end of the word
        else if (char === 'y' && i === s.length - 1) {
            count++;
        }
    }

    return count;
}
```

```javascript
function circular_shift(x, shift) {
    const s = String(x);
    const n = s.length;

    if (n === 0) return "";

    if (shift > n) {
        return s.split('').reverse().join('');
    }

    const effectiveShift = shift % n;
    if (effectiveShift === 0) {
        return s;
    }

    const rightPart = s.slice(n - effectiveShift);
    const leftPart = s.slice(0, n - effectiveShift);

    return rightPart + leftPart;
}
```

```javascript
function digitSum(s) {
    let sum = 0;
    for (let i = 0; i < s.length; i++) {
        const charCode = s.charCodeAt(i);
        if (charCode >= 65 && charCode <= 90) { // A-Z
            sum += charCode;
        }
    }
