```javascript
function pluck(arr) {
    let minEven = Infinity;
    let minIndex = -1;

    for (let i = 0; i < arr.length; i++) {
        const val = arr[i];
        if (val % 2 === 0) {
            if (val < minEven) {
                minEven = val;
                minIndex = i;
            }
        }
    }

    if (minIndex === -1) {
        return [];
    }

    return [minEven, minIndex];
}
```

```javascript
function search(lst) {
    const freq = {};
    for (const num of lst) {
        freq[num] = (freq[num] || 0) + 1;
    }

    let result = -1;
    for (const key in freq) {
        const num = parseInt(key);
        if (num > 0 && freq[key] >= num) {
            if (num > result) {
                result = num;
            }
        }
    }

    return result;
}
```

```javascript
function strange_sort_list(lst) {
    if (lst.length === 0) return [];

    const sorted = [...lst].sort((a, b) => a - b);
    const result = [];
    let left = 0;
    let right = sorted.length - 1;
    let pickMin = true;

    while (left <= right) {
        if (pickMin) {
            result.push(sorted[left]);
            left++;
        } else {
            result.push(sorted[right]);
            right--;
        }
        pickMin = !pickMin;
    }

    return result;
}
```

```javascript
function triangle_area(a, b, c) {
    if (a + b <= c || a + c <= b || b + c <= a) {
        return -1;
    }
    const s = (a + b + c) / 2;
    const area = Math.sqrt(s * (s - a) * (s - b) * (s - c));
    return Math.round(area * 100) / 100;
}
```

```javascript
function will_it_fly(q, w) {
    // Check if the array is a palindrome (balanced)
    const isBalanced = q.every((val, idx) => val === q[q.length - 1 - idx]);

    // Calculate the sum of elements
    const sum = q.reduce((acc, val) => acc + val, 0);

    // Check if sum is less than or equal to maximum weight w
    const withinWeight = sum <= w;

    return isBalanced && withinWeight;
}
```

```javascript
function smallest_change(arr) {
    let changes = 0;
    let left = 0;
    let right = arr.length - 1;

    while (left < right) {
        if (arr[left] !== arr[right]) {
            changes++;
        }
        left++;
        right--;
    }

    return changes;
}
