function is_multiply_prime(a) {
    const primes = [];
    for (let i = 2; i < a; i++) {
        let isPrime = true;
        for (let j = 2; j * j <= i; j++) {
            if (i % j === 0) {
                isPrime = false;
                break;
            }
        }
        if (isPrime) {
            primes.push(i);
        }
    }

    for (let i = 0; i < primes.length; i++) {
        for (let j = i; j < primes.length; j++) {
            for (let k = j; k < primes.length; k++) {
                if (primes[i] * primes[j] * primes[k] === a) {
                    return true;
                }
            }
        }
    }

    return false;
}

