        // For negative base, the sign of n^k alternates
        // We check both positive and negative exponents conceptually, 
        // but since k must be integer, let's just compute powers until we exceed |x|

        let power = 1;
        for (let k = 0; ; k++) {
            if (power === x) return true;
            if (Math.abs(power) > Math.abs(x)) break;
